    for i_0xI1lIIl=1, #d_0xIll1lI, 4 do
        local c_0xl11II1 = b64_0xIllIIl[d_0xIll1lI:sub(i_0xI1lIIl,i_0xI1lIIl)] or 0
        local c_0xI11lI1 = b64_0xIllIIl[d_0xIll1lI:sub(i_0xI1lIIl+1,i_0xI1lIIl+1)] or 0
        local c_0x1lIIl1, c_0x1ll111 = 0, 0
        local has3 = true
        local has4 = true
        local ch3 = d_0xIll1lI:sub(i_0xI1lIIl+2,i_0xI1lIIl+2)
        if ch3 == "=" then has3 = false else c_0x1lIIl1 = b64_0xIllIIl[ch3] or 0 end
        local ch4 = d_0xIll1lI:sub(i_0xI1lIIl+3,i_0xI1lIIl+3)
        if ch4 == "=" then has4 = false else c_0x1ll111 = b64_0xIllIIl[ch4] or 0 end
        local b_0xlIIl1I = c_0xl11II1 * (2^18) + c_0xI11lI1 * (2^12) + c_0x1lIIl1 * (2^6) + c_0x1ll111
        local b_0xI1Il1I = math.floor(b_0xlIIl1I / (2^16)) % (2^8)
        local b_0xlI1IIl = math.floor(b_0xlIIl1I / (2^8)) % (2^8)
        local b_0xlllI1l = b_0xlIIl1I % (2^8)
        table.insert(r_0xl1lIll, string.char(b_0xI1Il1I))
        if has3 then table.insert(r_0xl1lIll, string.char(b_0xlI1IIl)) end
        if has4 then table.insert(r_0xl1lIll, string.char(b_0xlllI1l)) end
    end
    return table.concat(r_0xl1lIll)
