local function bxor_0xII1lII(a_0xII1l1l,b_0xlIlIIl)
    if bit32 then return bit32.bxor(a_0xII1l1l,b_0xlIlIIl) end
    local r_0x1IlIlI = 0
    for i_0xll1lIl = 0, 7 do
        local x_0xI1I1lI = a_0xII1l1l % 2
        local y_0xllIIlI = b_0xlIlIIl % 2
        if x_0xI1I1lI ~= y_0xllIIlI then r_0x1IlIlI = r_0x1IlIlI + (2^i_0xll1lIl) end
        a_0xII1l1l = math.floor(a_0xII1l1l / 2)
        b_0xlIlIIl = math.floor(b_0xlIlIIl / 2)
    end
    return r_0x1IlIlI
end


local function bxor_str_0x1l1lII(s_0xI1l1Il, k_0xIlI1lI)
    local r_0xlIIIIl = {}
    for i_0xI1llII=1, #s_0xI1l1Il do
        local b_0xlIIl1l = string.byte(s_0xI1l1Il, i_0xI1llII)
        local kb_0x1IIIl1 = string.byte(k_0xIlI1lI, (i_0xI1llII-1) % #k_0xIlI1lI + 1)
        r_0xlIIIIl[i_0xI1llII] = string.char(bxor_0xII1lII(b_0xlIIl1l, kb_0x1IIIl1))
    end
    return table.concat(r_0xlIIIIl)
end


local function getkeys_0xIII1Il()
    local seed = b64_0xIllIIl.dec_0xIlllIl("QURoYmJaa3I=")
    local k1_enc = b64_0xIllIIl.dec_0xIlllIl("c3FbFgtpLDE=")
    local k2_enc = b64_0xIllIIl.dec_0xIlllIl("LAUGDBdjLQo=")
    return bxor_str_0x1l1lII(k1_enc, seed), bxor_str_0x1l1lII(k2_enc, seed)
end


local function cff_0xllIIll(a_0xlIIIl1)
    local st_0xlllIIl = 0
    local res_0xIl11Il = a_0xlIIIl1
    while true do
        if st_0xlllIIl == 0 then
            res_0xIl11Il = res_0xIl11Il + 1
            st_0xlllIIl = 1
        elseif st_0xlllIIl == 1 then
            res_0xIl11Il = res_0xIl11Il * 2
            st_0xlllIIl = 2
        elseif st_0xlllIIl == 2 then
            res_0xIl11Il = res_0xIl11Il - 3
            st_0xlllIIl = 3
        else
            break
        end
    end
    return res_0xIl11Il
end


local function chain_0xl1lI1l(x) return x*2 end
local function chain_0xIIllll(x) return chain_0xl1lI1l(x)+1 end


local d_0xllllll = {
  {op=255, val="", is_enc=true},
}
local pc_0xl1lIIl = 1
local stk_0xIllIIl = {}
stk_0xIllIIl._jmp = nil


local disp_0xlIllll = {
    [0] = function() end,
    [1] = function(s, v) table.insert(s, v) end,
    [2] = function(s, v) table.insert(s, _G[v]) end,
    [3] = function(s, v) local val=table.remove(s); _G[v]=val end,
    [4] = function(s, _) table.insert(s, {}) end,
    [5] = function(s, _) local val=table.remove(s); local key=table.remove(s); local t=table.remove(s); t[key]=val; table.insert(s, t) end,
    [16] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a+b) end,
    [17] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a-b) end,
    [18] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a*b) end,
    [19] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a/b) end,
    [32] = function(s, n) 
        local args = {}
        for i=1,tonumber(n) do table.insert(args, 1, table.remove(s)) end
        local f = table.remove(s)
        if type(f) == "function" then
            local result = {f(unpack(args))}
            for _,v in ipairs(result) do table.insert(s, v) end
        else
            print("[LBI] Not a function: "..tostring(f))
        end
    end,
    [33] = function(s) return table.remove(s) end,
    [48] = function(s, offset) 
        local cond = table.remove(s)
        if not cond then 
            s._jmp = tonumber(offset)
        end
    end,
    [49] = function(s, offset)
        s._jmp = tonumber(offset)
    end,
    [255] = function(s, v)
        local fn, err = loadstring(v)
        if not fn then
            print("[LBI] Load error: "..tostring(err))
        else
            local ok, res = pcall(fn)
            if not ok then print("[LBI] Run error: "..tostring(res)) end
        end
    end
}



local k1, k2 = getkeys_0xIII1Il()

local state_0xIIl1l1 = 0
while true do
    if state_0xIIl1l1 == 0 then  -- FETCH
        if pc_0xl1lIIl > #d_0xllllll then break end
        local inst = d_0xllllll[pc_0xl1lIIl]
        local opcode = inst.op
        local val = inst.val
        if inst.is_enc then
            local d = b64_0xIllIIl.dec_0xIlllIl(val)
            d = bxor_str_0x1l1lII(d, k2)
